let toastT;
function showToast(m){const t=document.getElementById('toast');document.getElementById('toast-msg').textContent=m;t.classList.add('show');clearTimeout(toastT);toastT=setTimeout(()=>t.classList.remove('show'),3000)}
function openModal(title,html){document.getElementById('modal-title').textContent=title;document.getElementById('modal-body').innerHTML=html;document.getElementById('modal-overlay').classList.remove('hidden');lucide.createIcons()}
function closeModal(){document.getElementById('modal-overlay').classList.add('hidden')}
document.getElementById('modal-overlay').addEventListener('click',e=>{if(e.target===document.getElementById('modal-overlay'))closeModal()});
function navigate(page,data){currentPage=page;selectedSize=null;selectedColor=0;appliedCoupon=null;document.querySelectorAll('.page').forEach(p=>p.classList.remove('active'));const el=document.getElementById('page-'+page);if(el)el.classList.add('active');const hide=['login','signup','admin'].includes(page);document.getElementById('main-nav').style.display=hide?'none':'';document.getElementById('main-footer').style.display=hide?'none':'';window.scrollTo({top:0,behavior:'smooth'});if(page==='home'){applyHero();renderHomeProducts();renderOffers()}if(page==='shop')renderShopPage();if(page==='product'&&data)renderProductDetail(data);if(page==='collections')renderCollectionsPage();if(page==='cart')renderCartPage();if(page==='checkout')renderCheckoutPage();if(page==='account')renderAccountPage();if(page==='story')renderStoryPage();if(page==='contact')renderContactPage();if(page==='admin'){if(!checkAdminSession()){requestAdminAccess();return}buildAdminNav();renderAdmin('overview')}if(page==='login'){const aw=document.getElementById('admin-link-wrapper');if(aw)aw.classList.add('hidden')}setTimeout(()=>{document.querySelectorAll('.anim:not(.visible)').forEach(el=>obs.observe(el));lucide.createIcons()},50);if(data&&page==='product')window.location.hash=page+'/'+data;else window.location.hash=page}
window.addEventListener('hashchange',()=>{const h=window.location.hash.slice(1);const[p,...r]=h.split('/');if(p&&p!==currentPage){if(p==='product'&&r[0])navigate('product',parseInt(r[0]));else navigate(p)}});
function toggleMobileMenu(){const m=document.getElementById('mobile-menu');m.classList.toggle('opacity-0');m.classList.toggle('pointer-events-none');document.body.style.overflow=m.classList.contains('opacity-0')?'':'hidden'}
function closeMobileMenu(){const m=document.getElementById('mobile-menu');m.classList.add('opacity-0','pointer-events-none');document.body.style.overflow=''}
function pc(p){return`<div class="pcard group cursor-pointer" onclick="navigate('product',${p.id})"><div class="relative overflow-hidden rounded-2xl aspect-[3/4] bg-cream"><img src="https://picsum.photos/seed/${p.img}/500/667.jpg" alt="${p.name}" class="pimg absolute inset-0 w-full h-full object-cover sepia-[0.15] opacity-75 transition-all duration-700" onerror="this.src='https://picsum.photos/seed/p${p.id}/500/667.jpg'"/><div class="pover absolute inset-0 bg-white/30 opacity-0 transition-opacity duration-300 flex items-center justify-center"><span class="bg-white text-brand-text text-xs font-medium uppercase tracking-widest px-6 py-3 rounded-full shadow-md">View</span></div>${p.badge?`<span class="absolute top-4 left-4 text-[10px] font-semibold tracking-[.15em] uppercase ${p.badge==='New'?'bg-rose-gold text-white':'bg-brand-text text-white'} px-3 py-1 rounded-full">${p.badge}</span>`:''}${p.soldOut?'<span class="absolute top-4 left-4 text-[10px] font-semibold tracking-[.15em] uppercase bg-brand-text text-white px-3 py-1 rounded-full">Sold Out</span>':''}</div><div class="mt-4 px-1"><h3 class="font-heading text-base font-medium tracking-tight">${p.name}</h3><p class="text-sm text-brand-muted mt-1">${p.material}</p><p class="text-sm font-medium mt-2 ${p.soldOut?'text-brand-faint line-through':''}">${fp(p.price)}</p></div></div>`}
function applyHero(){const img=document.getElementById('hero-img');if(img)img.src='https://picsum.photos/seed/'+(heroData.image||'senerova-hero-fash')+'/1920/1080.jpg';const b=document.getElementById('hero-badge');if(b)b.textContent=heroData.badge||'';const t1=document.getElementById('hero-t1');if(t1)t1.textContent=heroData.title1||'';const t2=document.getElementById('hero-t2');if(t2)t2.textContent=heroData.title2||'';const s=document.getElementById('hero-sub');if(s)s.textContent=heroData.subtitle||''}
function renderOffers(){const sec=document.getElementById('offers-section');const active=offersData.filter(o=>o.active);if(!active.length){sec.innerHTML='';sec.classList.add('hidden');return}sec.classList.remove('hidden');sec.innerHTML=`<div class="max-w-7xl mx-auto"><div class="text-center mb-12 anim"><span class="text-[10px] font-semibold tracking-[.3em] uppercase text-rose-gold">Special</span><h2 class="font-heading text-4xl md:text-6xl font-semibold tracking-tighter mt-3 uppercase">Offers</h2></div><div class="grid grid-cols-1 md:grid-cols-2 gap-6">${active.map(o=>`<div class="offer-card relative overflow-hidden rounded-2xl cursor-pointer group" onclick="navigate('${o.link}')"><div class="aspect-[16/9] md:aspect-[2/1]"><img src="https://picsum.photos/seed/${o.image}/900/450.jpg" class="oimg absolute inset-0 w-full h-full object-cover sepia-[0.15] opacity-80 transition-all duration-700"/></div><div class="absolute inset-0 bg-gradient-to-r from-brand-text/60 via-brand-text/30 to-transparent flex items-center p-8 md:p-12"><div><h3 class="font-heading text-2xl md:text-3xl font-semibold text-white">${o.title}</h3><p class="text-white/80 mt-2">${o.subtitle}</p><span class="inline-block mt-4 bg-white text-brand-text text-xs font-medium uppercase tracking-widest px-6 py-2.5 rounded-full shadow-md group-hover:bg-rose-gold group-hover:text-white transition-all duration-300">Shop Now</span></div></div></div>`).join('')}</div></div>`}
function renderHomeProducts(){document.getElementById('home-products').innerHTML=products.filter(p=>!p.soldOut).slice(0,4).map(pc).join('')}
/* renderShopPage stub — overridden by advanced IIFE below */
function renderShopPage(){renderShopProducts&&renderShopProducts()}
function renderShopProductsBasic(){document.getElementById('shop-products').innerHTML=products.map(pc).join('')}
function updateShopBtns(){document.querySelectorAll('.scb').forEach(b=>{const m=b.textContent.trim()===shopFilter;b.classList.toggle('active',m);b.classList.toggle('bg-rose-gold',m);b.classList.toggle('text-white',m);b.classList.toggle('text-brand-muted',!m)})}
function renderShopProducts(){const s=(document.getElementById('shop-search')?.value||'').toLowerCase(),so=document.getElementById('shop-sort')?.value||'newest';let f=products.filter(p=>{if(shopFilter!=='all'&&p.category!==shopFilter&&p.collection!==shopFilter)return false;if(s&&!p.name.toLowerCase().includes(s)&&!p.material.toLowerCase().includes(s))return false;return true});if(so==='price-asc')f.sort((a,b)=>a.price-b.price);if(so==='price-desc')f.sort((a,b)=>b.price-a.price);if(so==='name')f.sort((a,b)=>a.name.localeCompare(b.name));document.getElementById('shop-products').innerHTML=f.length?f.map(pc).join(''):'<div class="col-span-full text-center py-20 text-brand-faint">No products found</div>'}
function renderStars(r){let s='';for(let i=1;i<=5;i++)s+=`<span class="${i<=Math.round(r)?'star-fill':'star-empty'} text-sm">&#9733;</span>`;return s}
function renderProductDetail(id){const p=products.find(x=>x.id===id);if(!p)return;currentProductId=id;const rv=reviews[id]||[],avg=rv.length?Math.round(rv.reduce((s,r)=>s+r.rating,0)/rv.length*10)/10:0;const dist=[5,4,3,2,1].map(s=>({s,c:rv.filter(r=>r.rating===s).length})),mx=Math.max(...dist.map(r=>r.c),1);document.getElementById('product-detail').innerHTML=`<div class="space-y-4"><div class="overflow-hidden rounded-2xl aspect-[3/4] bg-cream"><img id="pd-img" src="https://picsum.photos/seed/${p.img}/800/1067.jpg" class="w-full h-full object-cover sepia-[0.15] opacity-80 hover:sepia-0 hover:opacity-90 transition-all duration-700"/></div><div class="grid grid-cols-4 gap-3">${[0,1,2,3].map(i=>`<div class="overflow-hidden rounded-lg aspect-square bg-cream cursor-pointer border border-transparent hover:border-rose-gold/30" onclick="document.getElementById('pd-img').src='https://picsum.photos/seed/${p.img}-v${i}/800/1067.jpg'"><img src="https://picsum.photos/seed/${p.img}-v${i}/200/200.jpg" class="w-full h-full object-cover sepia-[0.15] opacity-70"/></div>`).join('')}</div></div><div class="lg:py-4">${p.badge?`<span class="inline-block text-[10px] font-semibold tracking-[.15em] uppercase ${p.badge==='New'?'bg-rose-gold text-white':'bg-brand-text text-white'} px-3 py-1 rounded-full mb-4">${p.badge}</span>`:''}<h1 class="font-heading text-3xl md:text-4xl font-semibold tracking-tighter">${p.name}</h1><div class="flex items-center gap-3 mt-2"><p class="text-2xl font-heading font-medium ${p.soldOut?'text-brand-faint line-through':''}">${fp(p.price)}</p>${avg?`<div class="flex">${renderStars(avg)}</div><span class="text-sm text-brand-muted">${avg}</span>`:''}</div><div class="mt-2 flex items-center gap-2"><span class="w-2 h-2 rounded-full ${p.soldOut?'bg-red-400':'bg-green-500 pulse-dot'}"></span><span class="text-xs text-brand-muted">${p.soldOut?'Sold Out':'In Stock'}</span></div><p class="text-brand-muted font-light leading-relaxed mt-6">${p.desc}</p><div class="mt-6 pt-6 border-t border-[rgba(45,42,42,0.06)]"><p class="text-xs text-brand-faint uppercase tracking-widest mb-2">Material</p><p class="text-sm">${p.material}</p></div><div class="mt-6"><p class="text-xs text-brand-faint uppercase tracking-widest mb-3">Color &mdash; <span id="cl">${p.colorNames[0]}</span></p><div class="flex gap-3">${p.colors.map((c,i)=>`<button onclick="selectedColor=${i};document.getElementById('cl').textContent='${p.colorNames[i]}';document.querySelectorAll('.pdc').forEach((b,j)=>{b.style.outline=j===${i}?'2px solid #B76E79':'none';b.style.outlineOffset=j===${i}?'2px':'0'})" class="pdc w-8 h-8 rounded-full border border-[rgba(45,42,42,0.1)]" style="background:${c};${i===0?'outline:2px solid #B76E79;outline-offset:2px':''}"></button>`).join('')}</div></div><div class="mt-6"><p class="text-xs text-brand-faint uppercase tracking-widest mb-3">Size</p><div class="flex flex-wrap gap-2">${p.sizes.map(s=>`<button onclick="selectedSize='${s}';document.querySelectorAll('.size-btn').forEach(b=>b.classList.remove('active'));this.classList.add('active')" class="size-btn text-xs font-medium px-4 py-2.5 rounded-full border border-[rgba(45,42,42,0.08)] text-brand-muted hover:bg-blush/30 transition-all">${s}</button>`).join('')}</div></div><div class="mt-8 flex gap-3"><button onclick="addFromDetail(${p.id})" class="flex-1 bg-rose-gold text-white text-xs font-medium uppercase tracking-widest py-4 rounded-full hover:bg-rose-dark transition-colors ${p.soldOut?'opacity-40 pointer-events-none':''}">${p.soldOut?'Sold Out':'Add to Cart'}</button><button class="w-14 h-14 flex items-center justify-center border border-[rgba(45,42,42,0.08)] bg-white rounded-full hover:border-rose-gold/30 transition-colors"><i data-lucide="heart" class="w-5 h-5 text-brand-muted"></i></button></div><div class="mt-8 space-y-3"><details class="border-b border-[rgba(45,42,42,0.06)] pb-3"><summary class="text-sm font-medium cursor-pointer flex justify-between">Shipping & Returns <i data-lucide="chevron-down" class="w-4 h-4 text-brand-faint"></i></summary><p class="text-sm text-brand-muted mt-2 font-light">Free shipping on orders over ${fp(200)}. 30-day returns.</p></details><details class="border-b border-[rgba(45,42,42,0.06)] pb-3"><summary class="text-sm font-medium cursor-pointer flex justify-between">Care <i data-lucide="chevron-down" class="w-4 h-4 text-brand-faint"></i></summary><p class="text-sm text-brand-muted mt-2 font-light">Dry clean recommended.</p></details></div></div>`;document.getElementById('product-extras').innerHTML=`<div class="mb-16">${rv.length?`<div class="md:w-1/3 mb-8"><h3 class="font-heading text-2xl font-semibold tracking-tight">Reviews</h3><div class="mt-4 flex items-baseline gap-2"><span class="font-heading text-5xl font-semibold">${avg}</span><span class="text-brand-muted">/ 5</span></div><div class="mt-2 flex">${renderStars(avg)}</div><p class="text-sm text-brand-faint mt-1">${rv.length} review${rv.length>1?'s':''}</p><div class="mt-6 space-y-2">${dist.map(r=>`<div class="flex items-center gap-3"><span class="text-xs text-brand-muted w-3">${r.s}</span><div class="flex-1 h-2 bg-blush/20 rounded-full overflow-hidden"><div class="review-bar h-full bg-rose-gold rounded-full" style="width:${(r.c/mx*100)}%"></div></div><span class="text-xs text-brand-faint w-6 text-right">${r.c}</span></div>`).join('')}</div></div>`:''}<div class="bg-cream rounded-2xl p-6 mb-6 border border-[rgba(45,42,42,0.04)]"><h4 class="font-heading font-medium mb-4">Write a Review</h4>${!currentUser?'<p class="text-sm text-brand-faint"><button onclick="navigate(\'login\')" class="text-rose-gold hover:underline">Sign in</button> to review.</p>':`<div class="flex gap-1 mb-4" id="rv-stars">${[1,2,3,4,5].map(i=>`<button onclick="reviewRating=${i};document.querySelectorAll('.rvs').forEach((b,j)=>{b.classList.toggle('star-fill',j<${i});b.classList.toggle('star-empty',j>=${i})})" class="rvs text-2xl star-empty transition-colors">&#9733;</button>`).join('')}</div><input id="rv-title" placeholder="Review title" class="w-full bg-white border border-[rgba(45,42,42,0.08)] rounded-lg px-4 py-3 text-sm mb-3"/><textarea id="rv-body" placeholder="Your thoughts..." rows="3" class="w-full bg-white border border-[rgba(45,42,42,0.08)] rounded-lg px-4 py-3 text-sm mb-3 resize-none"></textarea><button onclick="submitReview(${p.id})" class="bg-rose-gold text-white text-xs font-medium uppercase tracking-widest px-6 py-3 rounded-full hover:bg-rose-dark transition-colors">Submit</button>`}</div><div class="space-y-4">${rv.map(r=>`<div class="bg-cream rounded-2xl p-6 border border-[rgba(45,42,42,0.04)]"><div class="flex items-center gap-2"><span class="font-medium text-sm">${r.name}</span><div class="flex">${renderStars(r.rating)}</div><span class="text-xs text-brand-faint ml-auto">${r.date}</span></div><h5 class="font-medium text-sm mt-2">${r.title}</h5><p class="text-sm text-brand-muted mt-1 font-light">${r.body}</p></div>`).join('')}</div></div><h3 class="font-heading text-2xl font-semibold tracking-tight">You May Also Like</h3><div id="related-products" class="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-4 gap-6 mt-8"></div>`;document.getElementById('related-products').innerHTML=products.filter(x=>x.id!==p.id&&(x.category===p.category||x.collection===p.collection)).slice(0,4).map(pc).join('');lucide.createIcons()}
function submitReview(pid){if(!reviewRating){showToast('Select a star rating');return}const t=document.getElementById('rv-title').value.trim(),b=document.getElementById('rv-body').value.trim();if(!t||!b){showToast('Fill in title and body');return}if(!reviews[pid])reviews[pid]=[];reviews[pid].unshift({name:currentUser.name||'User',rating:reviewRating,title:t,body:b,date:new Date().toLocaleDateString('en-US',{year:'numeric',month:'short',day:'numeric'})});saveReviews();reviewRating=0;showToast('Review submitted!');renderProductDetail(pid)}
function addFromDetail(id){const p=products.find(x=>x.id===id);if(!p||p.soldOut)return;if(!selectedSize){showToast('Please select a size');return}const e=cart.find(c=>c.productId===id&&c.size===selectedSize&&c.color===selectedColor);if(e)e.quantity++;else cart.push({productId:id,name:p.name,price:p.price,size:selectedSize,color:selectedColor,colorName:p.colorNames[selectedColor],quantity:1,img:p.img});saveCart();updateCartCount();showToast(p.name+' added to bag')}
function renderCollectionsPage(){document.getElementById('collections-grid').innerHTML=collections.map((c,i)=>`<div class="grid grid-cols-1 md:grid-cols-2 gap-0 rounded-2xl overflow-hidden border border-[rgba(45,42,42,0.06)] bg-white shadow-sm"><div class="overflow-hidden ${i%2?'md:order-2':''}"><img src="https://picsum.photos/seed/${c.img}/800/600.jpg" class="w-full h-72 md:h-full object-cover sepia-[0.15] opacity-70 hover:opacity-90 hover:sepia-0 transition-all duration-700"/></div><div class="bg-cream p-10 md:p-16 flex flex-col justify-center ${i%2?'md:order-1':''}"><span class="text-[10px] font-semibold tracking-[.3em] uppercase text-rose-gold">${products.filter(p=>p.collection===c.id).length} Pieces</span><h3 class="font-heading text-3xl md:text-5xl font-semibold tracking-tighter mt-3 uppercase">${c.name}</h3><p class="text-brand-muted font-light leading-relaxed mt-4">${c.desc}</p><button onclick="shopFilter='${c.id}';navigate('shop')" class="mt-8 inline-flex items-center gap-2 text-xs font-medium uppercase tracking-widest text-rose-gold hover:text-rose-dark transition-colors self-start">Explore <i data-lucide="arrow-right" class="w-4 h-4"></i></button></div></div>`).join('')}
function renderStoryPage(){const s=storyData;const _esc=t=>String(t??'').replace(/&/g,'&amp;').replace(/</g,'&lt;').replace(/>/g,'&gt;').replace(/"/g,'&quot;');document.getElementById('story-content').innerHTML=`<div class="pt-32 pb-20 px-6"><div class="max-w-7xl mx-auto"><div class="text-center mb-20 anim"><span class="text-[10px] font-semibold tracking-[.3em] uppercase text-rose-gold">Our Story</span><h2 class="font-heading text-4xl md:text-7xl font-semibold tracking-tighter mt-3 uppercase">Born From<br/>Restlessness</h2></div><div class="grid grid-cols-1 lg:grid-cols-2 gap-16 items-center mb-32 anim d1"><div class="overflow-hidden rounded-2xl"><img src="https://picsum.photos/seed/${_esc(s.heroImage)}/700/900.jpg" class="w-full aspect-[3/4] object-cover sepia-[0.15] opacity-70 hover:opacity-90 hover:sepia-0 transition-all duration-700"/></div><div><p class="text-brand-muted font-light leading-relaxed text-lg">${_esc(s.introText)}</p><p class="text-brand-muted font-light leading-relaxed mt-5">${_esc(s.bodyText)}</p><div class="grid grid-cols-3 gap-8 mt-12 pt-8 border-t border-[rgba(45,42,42,0.06)]">${(s.stats||[]).map(st=>`<div><div class="font-heading text-3xl font-semibold tracking-tighter">${_esc(st.value)}</div><div class="text-xs text-brand-faint mt-1 tracking-widest uppercase">${_esc(st.label)}</div></div>`).join('')}</div></div></div><div class="relative mb-16 anim"><div class="overflow-hidden rounded-2xl"><img src="https://picsum.photos/seed/${_esc(s.quoteImage)}/1400/500.jpg" class="w-full h-80 md:h-[500px] object-cover sepia-[0.2] opacity-60"/></div><div class="absolute inset-0 bg-gradient-to-t from-cream-bg via-transparent to-cream-bg"></div><div class="absolute bottom-8 left-8 right-8 text-center"><p class="font-heading text-xl md:text-3xl font-medium tracking-tight max-w-2xl mx-auto">${_esc(s.quoteText)}</p></div></div><div class="grid grid-cols-1 md:grid-cols-3 gap-8">${(s.values||[]).map((v,i)=>`<div class="bg-white border border-[rgba(45,42,42,0.06)] rounded-2xl p-8 shadow-sm anim d${i+1}"><div class="w-12 h-12 rounded-full bg-blush/30 flex items-center justify-center mb-5"><i data-lucide="${_esc(v.icon||'sparkles')}" class="w-5 h-5 text-rose-gold"></i></div><h3 class="font-heading text-lg font-semibold tracking-tight">${_esc(v.title)}</h3><p class="text-sm text-brand-muted mt-3 font-light leading-relaxed">${_esc(v.desc)}</p></div>`).join('')}</div></div></div>`;setTimeout(()=>{document.querySelectorAll('.anim:not(.visible)').forEach(el=>obs.observe(el));lucide.createIcons()},50)}
function renderCartPage(){const c=document.getElementById('cart-content');if(!cart.length){c.innerHTML='<div class="text-center py-24"><i data-lucide="shopping-bag" class="w-16 h-16 text-brand-faint mx-auto mb-6"></i><h3 class="font-heading text-2xl font-semibold tracking-tight">Your bag is empty</h3><button onclick="navigate(\'shop\')" class="mt-8 bg-rose-gold text-white text-xs font-medium uppercase tracking-widest px-8 py-4 rounded-full hover:bg-rose-dark transition-colors">Shop Now</button></div>';lucide.createIcons();return}const sub=cart.reduce((s,c)=>s+c.price*c.quantity,0);c.innerHTML=`<div class="grid grid-cols-1 lg:grid-cols-3 gap-12"><div class="lg:col-span-2 space-y-4">${cart.map((it,i)=>`<div class="flex gap-5 bg-white border border-[rgba(45,42,42,0.06)] rounded-2xl p-5 shadow-sm"><div class="w-24 h-32 rounded-lg overflow-hidden flex-shrink-0 bg-cream"><img src="https://picsum.photos/seed/${it.img}/200/267.jpg" class="w-full h-full object-cover sepia-[0.15] opacity-80"/></div><div class="flex-1"><div class="flex justify-between"><div><h4 class="font-heading font-medium tracking-tight">${it.name}</h4><p class="text-xs text-brand-muted mt-1">${it.colorName} / ${it.size}</p></div><button onclick="cart.splice(${i},1);saveCart();updateCartCount();renderCartPage()" class="text-brand-faint hover:text-red-500"><i data-lucide="x" class="w-4 h-4"></i></button></div><div class="flex items-center justify-between mt-4"><div class="flex items-center gap-3 border border-[rgba(45,42,42,0.08)] rounded-full bg-cream"><button onclick="cart[${i}].quantity=Math.max(1,cart[${i}].quantity-1);saveCart();renderCartPage()" class="w-8 h-8 flex items-center justify-center text-brand-muted hover:text-brand-text">&minus;</button><span class="text-sm font-medium w-6 text-center">${it.quantity}</span><button onclick="cart[${i}].quantity++;saveCart();renderCartPage()" class="w-8 h-8 flex items-center justify-center text-brand-muted hover:text-brand-text">+</button></div><p class="font-heading font-medium">${fp(it.price*it.quantity)}</p></div></div></div>`).join('')}</div><div><div class="bg-white border border-[rgba(45,42,42,0.06)] rounded-2xl p-8 shadow-sm sticky top-28"><h4 class="font-heading font-semibold tracking-tight mb-6">Summary</h4><div class="space-y-3 text-sm"><div class="flex justify-between text-brand-muted"><span>Subtotal</span><span>${fp(sub)}</span></div><div class="flex justify-between text-brand-muted"><span>Shipping</span><span>${sub>=200?'Free':fp(15)}</span></div></div><div class="border-t border-[rgba(45,42,42,0.06)] mt-4 pt-4 flex justify-between font-heading font-semibold"><span>Total</span><span>${fp(sub+(sub>=200?0:15))}</span></div>${sub<200?'<p class="text-xs text-rose-gold mt-3">Add '+fp(200-sub)+' more for free shipping</p>':''}<button onclick="navigate('checkout')" class="w-full bg-rose-gold text-white text-xs font-medium uppercase tracking-widest py-4 rounded-full hover:bg-rose-dark transition-colors mt-6">Checkout</button></div></div></div>`;lucide.createIcons()}
function renderCheckoutPage(){if(!cart.length){navigate('cart');return}const sub=cart.reduce((s,c)=>s+c.price*c.quantity,0),sh=sub>=200?0:15,disc=appliedCoupon?appliedCoupon.discount:0,total=sub+sh-disc;document.getElementById('checkout-content').innerHTML=`<div class="lg:col-span-3 space-y-8"><div class="bg-white border border-[rgba(45,42,42,0.06)] rounded-2xl p-8 shadow-sm"><h3 class="font-heading font-semibold tracking-tight mb-6">Contact</h3><input type="email" placeholder="Email" value="${currentUser?.email||''}" class="w-full bg-cream border border-[rgba(45,42,42,0.08)] rounded-lg px-4 py-3 text-sm"/></div><div class="bg-white border border-[rgba(45,42,42,0.06)] rounded-2xl p-8 shadow-sm"><h3 class="font-heading font-semibold tracking-tight mb-6">Shipping</h3><div class="grid grid-cols-2 gap-4"><input placeholder="First name" class="bg-cream border border-[rgba(45,42,42,0.08)] rounded-lg px-4 py-3 text-sm"/><input placeholder="Last name" class="bg-cream border border-[rgba(45,42,42,0.08)] rounded-lg px-4 py-3 text-sm"/><input placeholder="Address" class="bg-cream border border-[rgba(45,42,42,0.08)] rounded-lg px-4 py-3 text-sm col-span-2"/><input placeholder="City" class="bg-cream border border-[rgba(45,42,42,0.08)] rounded-lg px-4 py-3 text-sm"/><input placeholder="Postal code" class="bg-cream border border-[rgba(45,42,42,0.08)] rounded-lg px-4 py-3 text-sm"/><select class="bg-cream border border-[rgba(45,42,42,0.08)] rounded-lg px-4 py-3 text-sm text-brand-muted"><option>Bangladesh</option><option>Germany</option><option>United States</option><option>Japan</option></select><input placeholder="Phone" class="bg-cream border border-[rgba(45,42,42,0.08)] rounded-lg px-4 py-3 text-sm"/></div></div><div class="bg-white border border-[rgba(45,42,42,0.06)] rounded-2xl p-8 shadow-sm"><h3 class="font-heading font-semibold tracking-tight mb-6">Payment</h3><div class="space-y-4"><input placeholder="Card number" maxlength="19" oninput="this.value=this.value.replace(/[^0-9 ]/g,'').replace(/(.{4})/g,'$1 ').trim()" class="bg-cream border border-[rgba(45,42,42,0.08)] rounded-lg px-4 py-3 text-sm"/><div class="grid grid-cols-2 gap-4"><input placeholder="MM/YY" maxlength="7" oninput="this.value=this.value.replace(/[^0-9/]/g,'');if(this.value.length===2&&!this.value.includes('/'))this.value+='/'" class="bg-cream border border-[rgba(45,42,42,0.08)] rounded-lg px-4 py-3 text-sm"/><input placeholder="CVC" maxlength="4" class="bg-cream border border-[rgba(45,42,42,0.08)] rounded-lg px-4 py-3 text-sm"/></div></div></div><div class="bg-white border border-[rgba(45,42,42,0.06)] rounded-2xl p-8 shadow-sm"><h3 class="font-heading font-semibold tracking-tight mb-4">Coupon Code</h3><div class="flex gap-3"><input id="coupon-input" placeholder="Enter code" value="${appliedCoupon?appliedCoupon.code:''}" class="flex-1 bg-cream border border-[rgba(45,42,42,0.08)] rounded-lg px-4 py-3 text-sm uppercase tracking-wider" ${appliedCoupon?'disabled':''}/><button onclick="${appliedCoupon?'removeCoupon()':'applyCoupon()'}" class="bg-rose-gold text-white text-xs font-medium uppercase tracking-widest px-6 py-3 rounded-full hover:bg-rose-dark transition-colors">${appliedCoupon?'Remove':'Apply'}</button></div><div id="coupon-msg" class="mt-3 text-sm">${appliedCoupon?'<span class="text-green-600">&#10003; '+appliedCoupon.code+' applied &mdash; saving '+fp(disc)+'</span>':''}</div></div><button onclick="placeOrder()" class="w-full bg-rose-gold text-white text-xs font-medium uppercase tracking-widest py-4 rounded-full hover:bg-rose-dark transition-colors">Place Order &mdash; ${fp(total)}</button></div><div class="lg:col-span-2"><div class="bg-white border border-[rgba(45,42,42,0.06)] rounded-2xl p-8 shadow-sm sticky top-28"><h4 class="font-heading font-semibold tracking-tight mb-6">Order</h4><div class="space-y-4">${cart.map(it=>`<div class="flex gap-4"><div class="w-16 h-20 rounded-lg overflow-hidden bg-cream flex-shrink-0"><img src="https://picsum.photos/seed/${it.img}/100/133.jpg" class="w-full h-full object-cover sepia-[0.15] opacity-80"/></div><div class="flex-1 min-w-0"><p class="text-sm font-medium truncate">${it.name}</p><p class="text-xs text-brand-faint">${it.colorName}/${it.size} x${it.quantity}</p></div><p class="text-sm font-medium">${fp(it.price*it.quantity)}</p></div>`).join('')}</div><div class="border-t border-[rgba(45,42,42,0.06)] mt-6 pt-4 space-y-2 text-sm"><div class="flex justify-between text-brand-muted"><span>Subtotal</span><span>${fp(sub)}</span></div><div class="flex justify-between text-brand-muted"><span>Shipping</span><span>${sh?fp(sh):'Free'}</span></div>${disc?`<div class="flex justify-between text-green-600"><span>Discount (${appliedCoupon.code})</span><span>-${fp(disc)}</span></div>`:''}</div><div class="border-t border-[rgba(45,42,42,0.06)] mt-4 pt-4 flex justify-between font-heading font-semibold text-base"><span>Total</span><span>${fp(total)}</span></div></div></div>`;lucide.createIcons()}
function applyCoupon(){const code=document.getElementById('coupon-input').value.trim().toUpperCase();if(!code){showToast('Enter a coupon code');return}const coupon=couponsData.find(c=>c.code===code&&c.active);if(!coupon){showCouponMsg('Invalid or inactive coupon code',false);return}const sub=cart.reduce((s,c)=>s+c.price*c.quantity,0);if(coupon.usageLimit>0&&coupon.usedCount>=coupon.usageLimit){showCouponMsg('Coupon usage limit reached',false);return}if(sub<coupon.minOrder){showCouponMsg('Minimum order '+fp(coupon.minOrder)+' required',false);return}if(coupon.categories.length&&!cart.some(c=>{const p=products.find(x=>x.id===c.productId);return p&&coupon.categories.includes(p.category)})){showCouponMsg('Not applicable to items in cart',false);return}if(coupon.collections.length&&!cart.some(c=>{const p=products.find(x=>x.id===c.productId);return p&&coupon.collections.includes(p.collection)})){showCouponMsg('Not applicable to items in cart',false);return}let discount=coupon.type==='percentage'?Math.round(sub*coupon.value/100):coupon.value;if(coupon.maxDiscount>0)discount=Math.min(discount,coupon.maxDiscount);appliedCoupon={...coupon,discount};showCouponMsg('Coupon applied! You save '+fp(discount),true);renderCheckoutPage()}
function removeCoupon(){appliedCoupon=null;renderCheckoutPage()}
function showCouponMsg(msg,ok){const el=document.getElementById('coupon-msg');if(el)el.innerHTML=`<span class="${ok?'text-green-600':'text-red-500'}">${ok?'&#10003; ':''}${msg}</span>`}
function placeOrder(){if(!currentUser){showToast('Please sign in');navigate('login');return}const sub=cart.reduce((s,c)=>s+c.price*c.quantity,0),sh=sub>=200?0:15,disc=appliedCoupon?appliedCoupon.discount:0;if(appliedCoupon){const ci=couponsData.find(c=>c.id===appliedCoupon.id);if(ci)ci.usedCount++;saveCoupons()}mockOrders.unshift({id:'SN-2025-'+String(Math.floor(Math.random()*900)+100),customer:currentUser.name,email:currentUser.email,items:cart.length,total:sub+sh-disc,status:'Processing',date:new Date().toISOString().slice(0,10),address:'\u2014',phone:'\u2014',coupon:appliedCoupon?appliedCoupon.code:''});saveOrders();cart=[];saveCart();updateCartCount();appliedCoupon=null;document.getElementById('checkout-content').innerHTML='<div class="col-span-full text-center py-24"><div class="w-20 h-20 rounded-full bg-green-100 flex items-center justify-center mx-auto mb-6"><i data-lucide="check" class="w-10 h-10 text-green-600"></i></div><h3 class="font-heading text-3xl font-semibold tracking-tighter">Order Confirmed</h3><p class="text-brand-muted mt-3">Thank you, '+currentUser.name+'.</p><button onclick="navigate(\'shop\')" class="mt-8 bg-rose-gold text-white text-xs font-medium uppercase tracking-widest px-8 py-4 rounded-full hover:bg-rose-dark transition-colors">Continue Shopping</button></div>';lucide.createIcons()}
