function handleUserClick(){if(currentUser)navigate('account');else navigate('login')}
function validateEmail(e){return/^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(e)}
function validatePassword(p){return p.length>=8}

/* --- Login rate limiting --- */
const _loginAttempts={count:0,lockedUntil:0};
async function handleLogin(e){
  e.preventDefault();
  const now=Date.now();
  if(_loginAttempts.lockedUntil>now){
    showToast('Too many attempts. Wait '+(Math.ceil((_loginAttempts.lockedUntil-now)/1000))+'s');
    return;
  }

  const email=document.getElementById('login-email').value.trim().toLowerCase();
  const pass=document.getElementById('login-pass').value;

  if(!validateEmail(email)){showToast('Enter a valid email address');return}
  if(!pass){showToast('Enter your password');return}

  // Direct admin login
  if(email==='admin@test.com' && pass==='Admin@2025'){
    const res=await AdminAuth.verify(pass);
    if(res.ok){
      _loginAttempts.count=0;
      showToast('Admin login successful');
      navigate('admin');
      return;
    }
  }

  _loginAttempts.count++;
  if(_loginAttempts.count>=5){
    _loginAttempts.lockedUntil=now+30000;
    _loginAttempts.count=0;
    showToast('Too many attempts. Locked for 30s.');
    return;
  }

  /* Simulate auth — replace with real backend call in production */
  const stored=JSON.parse(localStorage.getItem('sen-registered-users')||'[]');
  const match=stored.find(u=>u.email===email);
  if(match){
    _loginAttempts.count=0;
    currentUser={name:match.name,email:match.email,method:'email'};
    saveUser();
    showToast('Welcome back, '+currentUser.name.split(' ')[0]);
    navigate('home');
  }else{
    /* Demo: accept any valid email as login for prototype */
    _loginAttempts.count=0;
    currentUser={name:email.split('@')[0].replace(/[^a-zA-Z0-9 ]/g,' '),email:email,method:'email'};
    saveUser();
    showToast('Welcome back');
    navigate('home');
  }
}
function handleSignup(e){
  e.preventDefault();
  const first=document.getElementById('signup-first').value.trim();
  const last=document.getElementById('signup-last').value.trim();
  const email=document.getElementById('signup-email').value.trim();
  const pass=document.getElementById('signup-pass').value;
  if(!first||!last){showToast('Enter your full name');return}
  if(!validateEmail(email)){showToast('Enter a valid email address');return}
  if(!validatePassword(pass)){showToast('Password must be at least 8 characters');return}
  if(!/[A-Z]/.test(pass)||!/[0-9]/.test(pass)){showToast('Password needs an uppercase letter and a number');return}
  const stored=JSON.parse(localStorage.getItem('sen-registered-users')||'[]');
  if(stored.find(u=>u.email===email)){showToast('An account with this email already exists');return}
  /* Store name only — NEVER store plaintext passwords client-side in production */
  stored.push({name:first+' '+last,email:email});
  localStorage.setItem('sen-registered-users',JSON.stringify(stored));
  currentUser={name:first+' '+last,email:email,method:'email'};
  saveUser();showToast('Welcome to Senerova, '+first+'!');navigate('home')
}
