/* ============================================================
   ADMIN SECURITY MODULE
   - Default password: Admin@2025
   - Sessions expire after 2 hours (sessionStorage)
   - 5 failed attempts trigger 30s lockout
   - Change password via Admin > Settings
   ============================================================ */
const AdminAuth=(()=>{
  const SESSION_KEY='sen-admin-session';
  const HASH_KEY='sen-admin-hash';
  const SALT='senerova-2025-salt';
  const SESSION_TTL=2*60*60*1000; // 2 hours
  let _lockUntil=0,_attempts=0;

  async function hashPassword(pw){
    const enc=new TextEncoder();
    const buf=await crypto.subtle.digest('SHA-256',enc.encode(pw+SALT));
    return Array.from(new Uint8Array(buf)).map(b=>b.toString(16).padStart(2,'0')).join('');
  }

  async function getStoredHash(){
    let h=localStorage.getItem(HASH_KEY);
    if(!h){h=await hashPassword('Admin@2025');localStorage.setItem(HASH_KEY,h)}
    return h;
  }

  function createSession(){
    const exp=Date.now()+SESSION_TTL;
    sessionStorage.setItem(SESSION_KEY,JSON.stringify({exp,token:Math.random().toString(36).slice(2)}));
  }

  function isSessionValid(){
    try{const s=JSON.parse(sessionStorage.getItem(SESSION_KEY)||'{}');return s.exp&&s.exp>Date.now()}
    catch{return false}
  }

  function clearSession(){sessionStorage.removeItem(SESSION_KEY)}

  async function verify(pw){
    if(Date.now()<_lockUntil)return{ok:false,locked:true,wait:Math.ceil((_lockUntil-Date.now())/1000)};
    const h=await hashPassword(pw);
    const stored=await getStoredHash();
    if(h===stored){_attempts=0;createSession();return{ok:true}}
    _attempts++;
    if(_attempts>=5){_lockUntil=Date.now()+30000;_attempts=0;return{ok:false,locked:true,wait:30}}
    return{ok:false,locked:false,remaining:5-_attempts}
  }

  async function changePassword(oldPw,newPw){
    const res=await verify(oldPw);
    if(!res.ok)return{ok:false,msg:'Current password incorrect'};
    if(newPw.length<8||!/[A-Z]/.test(newPw)||!/[0-9]/.test(newPw))
      return{ok:false,msg:'New password: min 8 chars, one uppercase, one number'};
    const h=await hashPassword(newPw);
    localStorage.setItem(HASH_KEY,h);
    return{ok:true};
  }

  return{verify,isSessionValid,clearSession,changePassword};
})();

function checkAdminSession(){return AdminAuth.isSessionValid()}

function requestAdminAccess(){
  document.getElementById('admin-gate-pass').value='';
  document.getElementById('admin-gate-error').classList.add('hidden');
  document.getElementById('admin-gate-locked').classList.add('hidden');
  document.getElementById('admin-auth-gate').classList.remove('hidden');
  setTimeout(()=>document.getElementById('admin-gate-pass').focus(),100);
}

function closeAdminGate(){
  document.getElementById('admin-auth-gate').classList.add('hidden');
  if(currentPage==='admin')navigate('login');
}

async function submitAdminGate(){
  const pw=document.getElementById('admin-gate-pass').value;
  if(!pw){showToast('Enter admin password');return}
  const res=await AdminAuth.verify(pw);
  if(res.locked){
    document.getElementById('admin-gate-timer').textContent=res.wait;
    document.getElementById('admin-gate-locked').classList.remove('hidden');
    document.getElementById('admin-gate-error').classList.add('hidden');
    let t=res.wait;const iv=setInterval(()=>{t--;document.getElementById('admin-gate-timer').textContent=t;if(t<=0)clearInterval(iv)},1000);
    return;
  }
  if(res.ok){
    document.getElementById('admin-auth-gate').classList.add('hidden');
    buildAdminNav();renderAdmin('overview');
    /* Activate admin page */
    document.querySelectorAll('.page').forEach(p=>p.classList.remove('active'));
    const el=document.getElementById('page-admin');if(el)el.classList.add('active');
    document.getElementById('main-nav').style.display='none';
    document.getElementById('main-footer').style.display='none';
    window.location.hash='admin';
    currentPage='admin';
    setTimeout(()=>lucide.createIcons(),100);
    return;
  }
  document.getElementById('admin-gate-attempts').textContent=res.remaining;
  document.getElementById('admin-gate-error').classList.remove('hidden');
  document.getElementById('admin-gate-pass').value='';
  document.getElementById('admin-gate-pass').focus();
}

function adminLogout(){AdminAuth.clearSession();navigate('home');showToast('Admin session ended')}

async function changeAdminPassword(){
  const oldPw=document.getElementById('set-old-pw')?.value||'';
  const newPw=document.getElementById('set-new-pw')?.value||'';
  const conf=document.getElementById('set-confirm-pw')?.value||'';
  const msgEl=document.getElementById('set-pw-msg');
  function showMsg(msg,ok){if(msgEl){msgEl.textContent=msg;msgEl.className='text-xs '+(ok?'text-green-600':'text-red-500');msgEl.classList.remove('hidden')}}
  if(!oldPw||!newPw||!conf){showMsg('All fields required',false);return}
  if(newPw!==conf){showMsg('New passwords do not match',false);return}
  const res=await AdminAuth.changePassword(oldPw,newPw);
  showMsg(res.msg||(res.ok?'Password updated successfully!':'Error'),res.ok);
  if(res.ok){document.getElementById('set-old-pw').value='';document.getElementById('set-new-pw').value='';document.getElementById('set-confirm-pw').value=''}
}
