function startOtpTimer(){let s=30;const b=document.getElementById('resend-btn'),t=document.getElementById('resend-timer');b.disabled=true;b.classList.add('text-brand-faint');b.classList.remove('text-rose-gold');t.textContent='('+s+'s)';t.classList.remove('hidden');if(otpTimer)clearInterval(otpTimer);otpTimer=setInterval(()=>{s--;t.textContent='('+s+'s)';if(s<=0){clearInterval(otpTimer);otpTimer=null;b.disabled=false;b.classList.remove('text-brand-faint');b.classList.add('text-rose-gold');t.classList.add('hidden')}},1000)}
